using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.LandedCosts.Domain.Entities;
namespace verii_metivon_api.Modules.LandedCosts.Infrastructure.Persistence.Configurations;
public sealed class LandedCostTypeConfiguration:IEntityTypeConfiguration<LandedCostType>{public void Configure(EntityTypeBuilder<LandedCostType>e){e.ToTable("RII_LANDED_COST_TYPES");e.HasKey(x=>x.Id);e.Property(x=>x.Code).HasMaxLength(50).IsRequired();e.Property(x=>x.Name).HasMaxLength(150).IsRequired();e.HasIndex(x=>x.Code).IsUnique().HasFilter("[IsDeleted] = 0");e.HasQueryFilter(x=>!x.IsDeleted);e.HasOne(x=>x.ClearingAccount).WithMany().HasForeignKey(x=>x.ClearingAccountId).OnDelete(DeleteBehavior.Restrict);e.HasOne(x=>x.VarianceAccount).WithMany().HasForeignKey(x=>x.VarianceAccountId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class ImportDossierConfiguration:IEntityTypeConfiguration<ImportDossier>{public void Configure(EntityTypeBuilder<ImportDossier>e){e.ToTable("RII_IMPORT_DOSSIERS");e.HasKey(x=>x.Id);e.Property(x=>x.DossierNumber).HasMaxLength(50).IsRequired();e.HasIndex(x=>x.DossierNumber).IsUnique().HasFilter("[IsDeleted] = 0");e.Property(x=>x.CurrencyCode).HasMaxLength(3);e.Property(x=>x.IncotermCode).HasMaxLength(10);e.Property(x=>x.TransactionExchangeRate).HasPrecision(18,8);e.Property(x=>x.CustomsExchangeRate).HasPrecision(18,8);e.Property(x=>x.CostingExchangeRate).HasPrecision(18,8);e.HasQueryFilter(x=>!x.IsDeleted);e.HasOne(x=>x.Supplier).WithMany().HasForeignKey(x=>x.SupplierId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class ImportDossierLineConfiguration:IEntityTypeConfiguration<ImportDossierLine>{public void Configure(EntityTypeBuilder<ImportDossierLine>e){e.ToTable("RII_IMPORT_DOSSIER_LINES");e.HasKey(x=>x.Id);e.HasIndex(x=>new{x.ImportDossierId,x.LineNumber}).IsUnique();foreach(var p in new[]{nameof(ImportDossierLine.Quantity),nameof(ImportDossierLine.NetWeight),nameof(ImportDossierLine.GrossWeight),nameof(ImportDossierLine.Volume),nameof(ImportDossierLine.ForeignUnitPrice),nameof(ImportDossierLine.ForeignGoodsAmount),nameof(ImportDossierLine.GoodsAmountLocal),nameof(ImportDossierLine.AllocatedCostLocal),nameof(ImportDossierLine.FinalUnitCostLocal)})e.Property(p).HasPrecision(18,6);e.Property(x=>x.TransactionExchangeRate).HasPrecision(18,8);e.Property(x=>x.CustomsExchangeRate).HasPrecision(18,8);e.Property(x=>x.CostingExchangeRate).HasPrecision(18,8);e.HasQueryFilter(x=>!x.IsDeleted);e.HasOne(x=>x.ImportDossier).WithMany(x=>x.Lines).HasForeignKey(x=>x.ImportDossierId).OnDelete(DeleteBehavior.Cascade);e.HasOne(x=>x.PurchaseOrderLine).WithMany().HasForeignKey(x=>x.PurchaseOrderLineId).OnDelete(DeleteBehavior.Restrict);e.HasOne(x=>x.GoodsReceiptLine).WithMany().HasForeignKey(x=>x.GoodsReceiptLineId).OnDelete(DeleteBehavior.Restrict);e.HasOne(x=>x.ReceiptTransaction).WithMany().HasForeignKey(x=>x.ReceiptTransactionId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class ImportDossierCostConfiguration:IEntityTypeConfiguration<ImportDossierCost>{public void Configure(EntityTypeBuilder<ImportDossierCost>e){e.ToTable("RII_IMPORT_DOSSIER_COSTS");e.HasKey(x=>x.Id);e.Property(x=>x.CurrencyCode).HasMaxLength(3);e.Property(x=>x.ForeignAmount).HasPrecision(18,4);e.Property(x=>x.ExchangeRate).HasPrecision(18,8);e.Property(x=>x.LocalAmount).HasPrecision(18,4);e.HasQueryFilter(x=>!x.IsDeleted);e.HasOne(x=>x.ImportDossier).WithMany(x=>x.Costs).HasForeignKey(x=>x.ImportDossierId).OnDelete(DeleteBehavior.Cascade);e.HasOne(x=>x.LandedCostType).WithMany().HasForeignKey(x=>x.LandedCostTypeId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class ImportDossierAllocationConfiguration:IEntityTypeConfiguration<ImportDossierAllocation>{public void Configure(EntityTypeBuilder<ImportDossierAllocation>e){e.ToTable("RII_IMPORT_DOSSIER_ALLOCATIONS");e.HasKey(x=>x.Id);e.HasIndex(x=>new{x.ImportDossierCostId,x.ImportDossierLineId,x.Revision}).IsUnique();e.Property(x=>x.BasisValue).HasPrecision(18,6);e.Property(x=>x.AllocationRate).HasPrecision(18,10);e.Property(x=>x.AllocatedAmount).HasPrecision(18,4);e.HasQueryFilter(x=>!x.IsDeleted);e.HasOne(x=>x.ImportDossierCost).WithMany(x=>x.Allocations).HasForeignKey(x=>x.ImportDossierCostId).OnDelete(DeleteBehavior.Cascade);e.HasOne(x=>x.ImportDossierLine).WithMany(x=>x.Allocations).HasForeignKey(x=>x.ImportDossierLineId).OnDelete(DeleteBehavior.NoAction);}}
public sealed class ImportDossierDocumentConfiguration:IEntityTypeConfiguration<ImportDossierDocument>{public void Configure(EntityTypeBuilder<ImportDossierDocument>e){e.ToTable("RII_IMPORT_DOSSIER_DOCUMENTS");e.HasKey(x=>x.Id);e.HasIndex(x=>new{x.ImportDossierId,x.DocumentType});e.Property(x=>x.DocumentNumber).HasMaxLength(100);e.Property(x=>x.OriginalFileName).HasMaxLength(255).IsRequired();e.Property(x=>x.StoredFileName).HasMaxLength(255).IsRequired();e.Property(x=>x.ContentType).HasMaxLength(100).IsRequired();e.Property(x=>x.Sha256).HasMaxLength(64).IsRequired();e.HasQueryFilter(x=>!x.IsDeleted);e.HasOne(x=>x.ImportDossier).WithMany().HasForeignKey(x=>x.ImportDossierId).OnDelete(DeleteBehavior.Cascade);e.HasOne(x=>x.ImportDossierCost).WithMany().HasForeignKey(x=>x.ImportDossierCostId).OnDelete(DeleteBehavior.NoAction);}}
